     1→// FreeLang v6: Bytecode Compiler
     2→
     3→import { Expr, Stmt, Program, MatchArm } from "./ast";
     4→
     5→export enum Op {
     6→  Const, Pop, Dup,
     7→  Add, Sub, Mul, Div, Mod, Neg,
     8→  Eq, Neq, Lt, Gt, Lte, Gte,
     9→  And, Or, Not,
    10→  Jump, JumpIfFalse, JumpIfTrue,
    11→  Load, Store, LoadGlobal, StoreGlobal,
    12→  Call, Return, Builtin,
    13→  NewArray, Index, SetIndex,
    14→  NewObject, GetProp, SetProp,
    15→  NewClosure, LoadFree, StoreFree,
    16→  Print, Println,
    17→  TryBegin, TryEnd, Throw,
    18→  Iter, IterNext, IterDone,
    19→  AddrOf, Deref,  // v5.9.1: Pointer operators
    20→  // Phase 4: Unsafe 격리 레이어
    21→  Malloc, Free, Realloc,
    22→  UnsafeRead, UnsafeWrite,
    23→  UnsafeBegin, UnsafeEnd,
    24→  Halt,
    25→}
    26→
    27→export type Value =
    28→  | { tag: "num"; val: number }
    29→  | { tag: "str"; val: string }
    30→  | { tag: "bool"; val: boolean }
    31→  | { tag: "null" }
    32→  | { tag: "array"; val: Value[] }
    33→  | { tag: "object"; val: Map<string, Value> }
    34→  | { tag: "fn"; name: string; arity: number; addr: number; freeVars: Value[] }
    35→  | { tag: "builtin"; name: string }
    36→  | { tag: "iter"; val: Value[]; idx: number }
    37→  | { tag: "ptr"; addr: number; target?: Value }; // Pointer type (v5.9.1) - STEP 1: target is optional for HeapManager
    38→
    39→export type Chunk = {
    40→  code: number[];
    41→  constants: Value[];
    42→  lines: number[];
    43→};
    44→
    45→type Local = { name: string; depth: number };
    46→type Upvalue = { name: string; isLocal: boolean; index: number };
    47→type CompilerScope = {
    48→  locals: Local[];
    49→  depth: number;
    50→  upvalues: Upvalue[];
    51→};
    52→
    53→type LoopInfo = { startAddr: number; breakPatches: number[] };
    54→
    55→export function compile(program: Program): Chunk {
    56→  const chunk: Chunk = { code: [], constants: [], lines: [] };
    57→  const scopes: CompilerScope[] = [{ locals: [], depth: 0, upvalues: [] }];
    58→  const globals = new Set<string>();
    59→  const loopStack: LoopInfo[] = [];
    60→  const finallyStack: Stmt[][] = [];
    61→  const constCache = new Map<string, number>(); // Phase 5.4: 상수 중복 제거
    62→
    63→  function emit(op: Op, line = 0) { chunk.code.push(op); chunk.lines.push(line); }
    64→  function emitArg(op: Op, arg: number, line = 0) { emit(op, line); chunk.code.push(arg); chunk.lines.push(line); }
    65→  function addConst(val: Value): number {
    66→    // Phase 5.4: 상수 중복 제거 - 같은 값이면 기존 인덱스 반환
    67→    const key = JSON.stringify(val);
    68→    const existing = constCache.get(key);
    69→    if (existing !== undefined) return existing;
    70→    const idx = chunk.constants.length;
    71→    chunk.constants.push(val);
    72→    constCache.set(key, idx);
    73→    return idx;
    74→  }
    75→  function currentPos(): number { return chunk.code.length; }
    76→  function patchJump(pos: number) { chunk.code[pos + 1] = currentPos(); }
    77→
    78→  function scope(): CompilerScope { return scopes[scopes.length - 1]; }
    79→
    80→  function resolveLocal(name: string): number {
    81→    const locals = scope().locals;
    82→    for (let i = locals.length - 1; i >= 0; i--) {
    83→      if (locals[i].name === name) return i;
    84→    }
    85→    return -1;
    86→  }
    87→
    88→  function declareLocal(name: string) {
    89→    scope().locals.push({ name, depth: scope().depth });
    90→  }
    91→
    92→  function resolveUpvalue(name: string): number {
    93→    if (scopes.length < 2) return -1;
    94→    const s = scope();
    95→    for (let i = 0; i < s.upvalues.length; i++) {
    96→      if (s.upvalues[i].name === name) return i;
    97→    }
    98→    const parent = scopes[scopes.length - 2];
    99→    for (let j = parent.locals.length - 1; j >= 0; j--) {
   100→      if (parent.locals[j].name === name) {
   101→        s.upvalues.push({ name, isLocal: true, index: j });
   102→        return s.upvalues.length - 1;
   103→      }
   104→    }
   105→    for (let j = 0; j < parent.upvalues.length; j++) {
   106→      if (parent.upvalues[j].name === name) {
   107→        s.upvalues.push({ name, isLocal: false, index: j });
   108→        return s.upvalues.length - 1;
   109→      }
   110→    }
   111→    return -1;
   112→  }
   113→
   114→  function compileStmts(stmts: Stmt[]) {
   115→    for (const s of stmts) compileStmt(s);
   116→  }
   117→
   118→  // Compile statements where the last expr must leave a value on the stack
   119→  function compileStmtsAsExpr(stmts: Stmt[]) {
   120→    for (let i = 0; i < stmts.length; i++) {
   121→      const s = stmts[i];
   122→      const isLast = i === stmts.length - 1;
   123→
   124→      if (isLast && s.kind === "expr") {
   125→        // Last statement is an expression: compile it but DON'T pop
   126→        compileExpr(s.expr);
   127→      } else if (isLast && s.kind === "if") {
   128→        // Last statement is an if-statement in expression context
   129→        // Both branches must leave values on the stack
   130→        compileExpr(s.cond);
   131→        const jumpFalse = currentPos(); emitArg(Op.JumpIfFalse, 0);
   132→        compileStmtsAsExpr(s.then);
   133→        if (s.else) {
   134→          const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   135→          patchJump(jumpFalse);
   136→          compileStmtsAsExpr(s.else);
   137→          patchJump(jumpEnd);
   138→        } else {
   139→          // If-statement without else in expression context: push null as default
   140→          emitArg(Op.Const, addConst({ tag: "null" }));
   141→          const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   142→          patchJump(jumpFalse);
   143→          patchJump(jumpEnd);
   144→        }
   145→      } else {
   146→        compileStmt(s);
   147→      }
   148→    }
   149→  }
   150→
   151→  function compileStmt(s: Stmt) {
   152→    switch (s.kind) {
   153→      case "expr": compileExpr(s.expr); emit(Op.Pop); break;
   154→      case "let": {
   155→        if (scope().depth === 0) {
   156→          globals.add(s.name);
   157→          if (s.init) compileExpr(s.init); else emitArg(Op.Const, addConst({ tag: "null" }));
   158→          emitArg(Op.StoreGlobal, addConst({ tag: "str", val: s.name }));
   159→        } else {
   160→          declareLocal(s.name);
   161→          if (s.init) compileExpr(s.init); else emitArg(Op.Const, addConst({ tag: "null" }));
   162→          // Store the value in the local variable slot
   163→          emitArg(Op.Store, scope().locals.length - 1);
   164→        }
   165→        break;
   166→      }
   167→      case "fn": {
   168→        if (scope().depth === 0) globals.add(s.name);
   169→        else declareLocal(s.name);
   170→        compileFnBody(s.name, s.params, s.body);
   171→        if (scope().depth === 0) {
   172→          emitArg(Op.StoreGlobal, addConst({ tag: "str", val: s.name }));
   173→        }
   174→        break;
   175→      }
   176→      case "return": {
   177→        // Emit any pending finally blocks first
   178→        for (const fb of [...finallyStack].reverse()) {
   179→          compileStmts(fb);
   180→        }
   181→        if (s.value) compileExpr(s.value); else emitArg(Op.Const, addConst({ tag: "null" }));
   182→        emit(Op.Return);
   183→        break;
   184→      }
   185→      case "if": {
   186→        compileExpr(s.cond);
   187→        const jumpFalse = currentPos(); emitArg(Op.JumpIfFalse, 0);
   188→        compileStmts(s.then);
   189→        if (s.else) {
   190→          const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   191→          patchJump(jumpFalse);
   192→          compileStmts(s.else);
   193→          patchJump(jumpEnd);
   194→        } else {
   195→          patchJump(jumpFalse);
   196→        }
   197→        break;
   198→      }
   199→      case "while": {
   200→        const loop: LoopInfo = { startAddr: currentPos(), breakPatches: [] };
   201→        loopStack.push(loop);
   202→        compileExpr(s.cond);
   203→        const exit = currentPos(); emitArg(Op.JumpIfFalse, 0);
   204→        compileStmts(s.body);
   205→        emitArg(Op.Jump, loop.startAddr);
   206→        patchJump(exit);
   207→        for (const bp of loop.breakPatches) patchJump(bp);
   208→        loopStack.pop();
   209→        break;
   210→      }
   211→      case "for": {
   212→        // Compile iterator expression, store as global __iter_N
   213→        compileExpr(s.iter);
   214→        emit(Op.Iter);
   215→        const iterName = `__iter_${currentPos()}`;
   216→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: iterName }));
   217→        const loop: LoopInfo = { startAddr: currentPos(), breakPatches: [] };
   218→        loopStack.push(loop);
   219→        // Check done
   220→        emitArg(Op.LoadGlobal, addConst({ tag: "str", val: iterName }));
   221→        emit(Op.IterDone);
   222→        const exit = currentPos(); emitArg(Op.JumpIfTrue, 0);
   223→        // Get next value, store as loop variable
   224→        emitArg(Op.LoadGlobal, addConst({ tag: "str", val: iterName }));
   225→        emit(Op.IterNext);
   226→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: s.name }));
   227→        compileStmts(s.body);
   228→        emitArg(Op.Jump, loop.startAddr);
   229→        patchJump(exit);
   230→        for (const bp of loop.breakPatches) patchJump(bp);
   231→        loopStack.pop();
   232→        break;
   233→      }
   234→      case "block": {
   235→        scope().depth++;
   236→        compileStmts(s.body);
   237→        const localsToRemove = scope().locals.filter(l => l.depth === scope().depth).length;
   238→        for (let i = 0; i < localsToRemove; i++) { emit(Op.Pop); scope().locals.pop(); }
   239→        scope().depth--;
   240→        break;
   241→      }
   242→      case "break": {
   243→        if (loopStack.length === 0) throw new Error("break outside loop");
   244→        const bp = currentPos(); emitArg(Op.Jump, 0);
   245→        loopStack[loopStack.length - 1].breakPatches.push(bp);
   246→        break;
   247→      }
   248→      case "continue": {
   249→        if (loopStack.length === 0) throw new Error("continue outside loop");
   250→        emitArg(Op.Jump, loopStack[loopStack.length - 1].startAddr);
   251→        break;
   252→      }
   253→      case "print": {
   254→        compileExpr(s.expr);
   255→        emit(s.newline ? Op.Println : Op.Print);
   256→        break;
   257→      }
   258→      case "try": {
   259→        // Push finally block to stack if present
   260→        if (s.finallyBody.length > 0) {
   261→          finallyStack.push(s.finallyBody);
   262→        }
   263→
   264→        const tryBegin = currentPos(); emitArg(Op.TryBegin, 0); // catch addr
   265→        compileStmts(s.body);  // return inside here will see finallyStack
   266→        emit(Op.TryEnd);
   267→
   268→        // Pop finally block from stack after compiling try body
   269→        if (s.finallyBody.length > 0) {
   270→          finallyStack.pop();
   271→        }
   272→
   273→        const jumpFinally = currentPos(); emitArg(Op.Jump, 0);
   274→        // Catch
   275→        patchJump(tryBegin);
   276→        if (s.catchVar) {
   277→          scope().depth++;
   278→          declareLocal(s.catchVar);
   279→          compileStmts(s.catchBody);
   280→          const localsToRemove = scope().locals.filter(l => l.depth === scope().depth).length;
   281→          for (let i = 0; i < localsToRemove; i++) { emit(Op.Pop); scope().locals.pop(); }
   282→          scope().depth--;
   283→        } else {
   284→          emit(Op.Pop); // discard error
   285→          compileStmts(s.catchBody);
   286→        }
   287→        // Finally
   288→        patchJump(jumpFinally);
   289→        compileStmts(s.finallyBody);
   290→        break;
   291→      }
   292→      case "throw": {
   293→        compileExpr(s.expr);
   294→        emit(Op.Throw);
   295→        break;
   296→      }
   297→      case "struct": {
   298→        // Store struct definition as global with type metadata
   299→        globals.add(s.name);
   300→
   301→        // Create struct object with field information
   302→        const structVal = new Map<string, Value>();
   303→
   304→        // Add each field with null default
   305→        for (const field of s.fields) {
   306→          structVal.set(field.name, { tag: "null" });
   307→        }
   308→
   309→        // Store field metadata as JSON
   310→        const fieldMetadata = s.fields.map(f => ({ name: f.name, type: f.type }));
   311→        structVal.set("__fields__", { tag: "str", val: JSON.stringify(fieldMetadata) });
   312→        structVal.set("__struct_name__", { tag: "str", val: s.name });
   313→
   314→        emitArg(Op.Const, addConst({ tag: "object", val: structVal }));
   315→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: s.name }));
   316→        break;
   317→      }
   318→      case "import": break; // handled by module loader
   319→      case "export": compileStmt(s.stmt); break; // compile inner stmt
   320→      case "multi": compileStmts(s.stmts); break;
   321→      case "match": {
   322→        // Compile subject once, store as temp global
   323→        compileExpr(s.subject);
   324→        const tempName = `__match_${currentPos()}`;
   325→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: tempName }));
   326→        const endPatches: number[] = [];
   327→        for (const arm of s.arms) {
   328→          if (arm.pattern !== null) {
   329→            emitArg(Op.LoadGlobal, addConst({ tag: "str", val: tempName }));
   330→            compileExpr(arm.pattern);
   331→            emit(Op.Eq);
   332→            const skip = currentPos(); emitArg(Op.JumpIfFalse, 0);
   333→            compileStmts(arm.body);
   334→            endPatches.push(currentPos()); emitArg(Op.Jump, 0);
   335→            patchJump(skip);
   336→          } else {
   337→            // Default arm (_)
   338→            compileStmts(arm.body);
   339→          }
   340→        }
   341→        const end = currentPos();
   342→        for (const p of endPatches) patchJump(p);
   343→        break;
   344→      }
   345→      case "if-let": {
   346→        // If let: pattern matching with optional else
   347→        compileExpr(s.value);
   348→        const tempName = `__iflet_${currentPos()}`;
   349→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: tempName }));
   350→
   351→        // Compare value with pattern
   352→        emitArg(Op.LoadGlobal, addConst({ tag: "str", val: tempName }));
   353→        compileExpr(s.pattern);
   354→        emit(Op.Eq);
   355→
   356→        const skipBody = currentPos();
   357→        emitArg(Op.JumpIfFalse, 0);
   358→
   359→        // Execute body
   360→        compileStmts(s.body);
   361→
   362→        const skipElse = currentPos();
   363→        emitArg(Op.Jump, 0);
   364→
   365→        // Execute else (if exists)
   366→        patchJump(skipBody);
   367→        if (s.else) {
   368→          compileStmts(s.else);
   369→        }
   370→
   371→        patchJump(skipElse);
   372→        break;
   373→      }
   374→      case "while-let": {
   375→        // While let: repeat while pattern matches
   376→        const loopStart = currentPos();
   377→
   378→        // Evaluate value
   379→        compileExpr(s.value);
   380→        const tempName = `__whilelet_${currentPos()}`;
   381→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: tempName }));
   382→
   383→        // Try to match pattern
   384→        emitArg(Op.LoadGlobal, addConst({ tag: "str", val: tempName }));
   385→        compileExpr(s.pattern);
   386→        emit(Op.Eq);
   387→
   388→        const exit = currentPos();
   389→        emitArg(Op.JumpIfFalse, 0);
   390→
   391→        // Execute body
   392→        compileStmts(s.body);
   393→
   394→        // Loop back
   395→        emitArg(Op.Jump, loopStart);
   396→
   397→        patchJump(exit);
   398→        break;
   399→      }
   400→    }
   401→  }
   402→
   403→  function compileFnBody(name: string, params: string[], body: Stmt[]) {
   404→    const jumpOver = currentPos(); emitArg(Op.Jump, 0);
   405→    const fnAddr = currentPos();
   406→    scopes.push({ locals: [], depth: 1, upvalues: [] });
   407→    for (const p of params) declareLocal(p);
   408→    // Compile body as expression: last stmt should leave value on stack
   409→    if (body.length === 0) {
   410→      emitArg(Op.Const, addConst({ tag: "null" }));
   411→    } else {
   412→      compileStmtsAsExpr(body);
   413→    }
   414→    emit(Op.Return);
   415→    const fnScope = scopes.pop()!;
   416→    patchJump(jumpOver);
   417→
   418→    if (fnScope.upvalues.length > 0) {
   419→      for (const uv of fnScope.upvalues) {
   420→        if (uv.isLocal) emitArg(Op.Load, uv.index);
   421→        else emitArg(Op.LoadFree, uv.index);
   422→      }
   423→      emitArg(Op.Const, addConst({ tag: "fn", name, arity: params.length, addr: fnAddr, freeVars: [] }));
   424→      emitArg(Op.NewClosure, fnScope.upvalues.length);
   425→    } else {
   426→      emitArg(Op.Const, addConst({ tag: "fn", name, arity: params.length, addr: fnAddr, freeVars: [] }));
   427→    }
   428→  }
   429→
   430→  function compileExpr(e: Expr) {
   431→    switch (e.kind) {
   432→      case "number": emitArg(Op.Const, addConst({ tag: "num", val: e.value })); break;
   433→      case "string": emitArg(Op.Const, addConst({ tag: "str", val: e.value })); break;
   434→      case "bool": emitArg(Op.Const, addConst({ tag: "bool", val: e.value })); break;
   435→      case "null": emitArg(Op.Const, addConst({ tag: "null" })); break;
   436→      case "ident": {
   437→        const local = resolveLocal(e.name);
   438→        if (local !== -1) { emitArg(Op.Load, local); break; }
   439→        const upval = resolveUpvalue(e.name);
   440→        if (upval !== -1) { emitArg(Op.LoadFree, upval); break; }
   441→        emitArg(Op.LoadGlobal, addConst({ tag: "str", val: e.name }));
   442→        break;
   443→      }
   444→      case "binary": {
   445→        // Phase 5.4: 상수 폴딩 - 숫자 + 숫자 연산
   446→        if (e.left.kind === "number" && e.right.kind === "number") {
   447→          const l = e.left.value, r = e.right.value;
   448→          let result: Value | null = null;
   449→          if (e.op === "+") result = { tag: "num", val: l + r };
   450→          else if (e.op === "-") result = { tag: "num", val: l - r };
   451→          else if (e.op === "*") result = { tag: "num", val: l * r };
   452→          else if (e.op === "/" && r !== 0) result = { tag: "num", val: l / r };
   453→          else if (e.op === "%") result = { tag: "num", val: l % r };
   454→          else if (e.op === "==") result = { tag: "bool", val: l === r };
   455→          else if (e.op === "!=") result = { tag: "bool", val: l !== r };
   456→          else if (e.op === "<") result = { tag: "bool", val: l < r };
   457→          else if (e.op === ">") result = { tag: "bool", val: l > r };
   458→          else if (e.op === "<=") result = { tag: "bool", val: l <= r };
   459→          else if (e.op === ">=") result = { tag: "bool", val: l >= r };
   460→          if (result) { emitArg(Op.Const, addConst(result)); break; }
   461→        }
   462→        // Phase 5.4: 상수 폴딩 - 문자열 + 문자열
   463→        if (e.left.kind === "string" && e.right.kind === "string" && e.op === "+") {
   464→          emitArg(Op.Const, addConst({ tag: "str", val: e.left.value + e.right.value }));
   465→          break;
   466→        }
   467→
   468→        // 폴딩 불가능 → 기존 방식: 두 피연산자 컴파일 후 연산
   469→        compileExpr(e.left);
   470→        compileExpr(e.right);
   471→        const ops: Record<string, Op> = {
   472→          "+": Op.Add, "-": Op.Sub, "*": Op.Mul, "/": Op.Div, "%": Op.Mod,
   473→          "==": Op.Eq, "!=": Op.Neq, "<": Op.Lt, ">": Op.Gt, "<=": Op.Lte, ">=": Op.Gte,
   474→          "&&": Op.And, "||": Op.Or,
   475→        };
   476→        emit(ops[e.op]);
   477→        break;
   478→      }
   479→      case "unary": {
   480→        compileExpr(e.expr);
   481→        if (e.op === "-") emit(Op.Neg);
   482→        else if (e.op === "!" || e.op === "not") emit(Op.Not);
   483→        else if (e.op === "&") emit(Op.AddrOf);  // v5.9.1: Address-of operator
   484→        else if (e.op === "*") emit(Op.Deref);   // v5.9.1: Dereference operator
   485→        break;
   486→      }
   487→      case "call": {
   488→        compileExpr(e.callee); // Standard ident resolution: local → upvalue → global
   489→        for (const arg of e.args) compileExpr(arg);
   490→        emitArg(Op.Call, e.args.length);
   491→        break;
   492→      }
   493→      case "assign": {
   494→        compileExpr(e.value);
   495→        if (e.target.kind === "ident") {
   496→          const local = resolveLocal(e.target.name);
   497→          if (local !== -1) { emit(Op.Dup); emitArg(Op.Store, local); }
   498→          else {
   499→            const upval = resolveUpvalue(e.target.name);
   500→            if (upval !== -1) { emit(Op.Dup); emitArg(Op.StoreFree, upval); }
   501→            else { emit(Op.Dup); emitArg(Op.StoreGlobal, addConst({ tag: "str", val: e.target.name })); }
   502→          }
   503→        } else if (e.target.kind === "index") {
   504→          compileExpr(e.target.object);
   505→          compileExpr(e.target.index);
   506→          emit(Op.SetIndex);
   507→        } else if (e.target.kind === "member") {
   508→          compileExpr(e.target.object);
   509→          emitArg(Op.Const, addConst({ tag: "str", val: e.target.property }));
   510→          emit(Op.SetProp);
   511→        }
