  if (e.left.kind === "number" && e.right.kind === "number") {
    const l = e.left.value, r = e.right.value;
    let result: Value | null = null;
    if (e.op === "+") result = { tag: "num", val: l + r };
    else if (e.op === "-") result = { tag: "num", val: l - r };
    else if (e.op === "*") result = { tag: "num", val: l * r };
    else if (e.op === "/" && r !== 0) result = { tag: "num", val: l / r };
    else if (e.op === "%") result = { tag: "num", val: l % r };
    else if (e.op === "==") result = { tag: "bool", val: l === r };
    else if (e.op === "!=") result = { tag: "bool", val: l !== r };
    else if (e.op === "<") result = { tag: "bool", val: l < r };
    else if (e.op === ">") result = { tag: "bool", val: l > r };
    else if (e.op === "<=") result = { tag: "bool", val: l <= r };
    else if (e.op === ">=") result = { tag: "bool", val: l >= r };
